class HomeActivity extends AppCompatActivity {

    private static final String PREFS_NAME = "login_prefs";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_TOKEN = "key_token";
    private static final String KEY_LOGGED_IN = "key_logged_in";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (!isLoggedIn()) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(48, 64, 48, 48);

        EditText info = new EditText(this);
        info.setText(getWelcomeText());
        info.setEnabled(false);
        root.addView(info, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        Button logout = new Button(this);
        logout.setText("Logout");
        logout.setOnClickListener(v -> {
            clearCredentials();
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        });
        root.addView(logout, new LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
        ));

        setContentView(root);
    }

    private String getWelcomeText() {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        String email = prefs.getString(KEY_EMAIL, "user");
        String token = prefs.getString(KEY_TOKEN, "");
        return "Welcome, " + email + "\nToken: " + token;
    }

    private boolean isLoggedIn() {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        String token = prefs.getString(KEY_TOKEN, null);
        boolean loggedIn = prefs.getBoolean(KEY_LOGGED_IN, false);
        return loggedIn && !TextUtils.isEmpty(token);
    }

    private void clearCredentials() {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, MODE_PRIVATE);
        prefs.edit()
                .remove(KEY_EMAIL)
                .remove(KEY_TOKEN)
                .putBoolean(KEY_LOGGED_IN, false)
                .apply();
    }
}